// worker3.js - Configuration and security worker
export default {
  async fetch(request, env) {
    // Validate origin
    const origin = request.headers.get('Origin');
    if (origin && !isValidOrigin(origin)) {
      return new Response('Forbidden', { status: 403 });
    }
    
    // Rate limiting check
    const clientIP = request.headers.get('CF-Connecting-IP');
    if (await isRateLimited(clientIP, env)) {
      return new Response('Too many requests', { status: 429 });
    }
    
    return new Response('OK');
  }
};

function isValidOrigin(origin) {
  const allowedOrigins = ['https://yourdomain.com'];
  return allowedOrigins.includes(origin);
}

async function isRateLimited(clientIP, env) {
  const key = `rate_limit:${clientIP}`;
  const current = await env.RATE_LIMITER.get(key);
  
  if (current && parseInt(current) > 100) {
    return true;
  }
  
  await env.RATE_LIMITER.put(key, (parseInt(current) || 0) + 1, { expirationTtl: 60 });
  return false;
}